    grid = []
    lab = None
    for i in range(n):
        row = input().strip()
        grid.append(list(row))
        for j in range(len(row)):
            if row[j] == 'L':
                lab = (i, j)

    dirs = [(-1,0),(1,0),(0,-1),(0,1)]
    deg = [[0]*m for _ in range(n)]
    bad = [[0]*m for _ in range(n)]
    good = [[False]*m for _ in range(n)]

    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                for di,dj in dirs:
                    ni,nj = i+di,j+dj
                    if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#':
                        deg[i][j] += 1
                        bad[i][j] += 1

    q = deque()
    li, lj = lab
    good[li][lj] = True
    q.append((li,lj))

    while q:
        i,j = q.popleft()
        for di,dj in dirs:
            ni,nj = i+di,j+dj
            if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#' and not good[ni][nj]:
                bad[ni][nj] -= 1
                if bad[ni][nj] <= 1 and deg[ni][nj] >= 1:
                    good[ni][nj] = True
                    q.append((ni,nj))

    out = []
    for i in range(n):
        for j in range(m):
            if grid[i][j] == '.' and good[i][j]:
                grid[i][j] = '+'
        out.append(''.join(grid[i]))
    print('\n'.join(out))

t = int(input())
for _ in range(t):
    solve()

